var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>재건 도시 군 사단장으로부터 온 프라이빗 메일입니다.</color>`,JPN:`<color=#ffd34c>再建都市軍の師団長から届いたプライベートメールです。</color>`,ENG:`<color=#ffd34c>A private mail arrived from the Rebuilt City's Division Commander.</color>`,TWN:`<color=#ffd34c>來自重建城市軍事團長的機密郵件。</color>`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`도시 방어에 기여해 주신 태스크포스 분들에게 깊은 감사를 표합니다.`,JPN:`都市の防衛に貢献してくださった
タスクフォースカンパニーの皆様には心より感謝申し上げます。`,ENG:`I would like to thank everyone at the TASKFORCE for helping us defend our city.`,TWN:`我在此由衷地感謝各方特遣勢力公司為城市防禦做出的貢獻。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`사로잡은 사교도의 말에 따르면 그들에겐 <color=#ffd34c>천사</color>라는 배후세력이 있는 듯 합니다.`,JPN:`捕らえた邪教徒の話では、彼らには
<color=#ffd34c>天使</color>と呼ばれる背後勢力がいるようです。`,ENG:`According to the captured cultists, they are being controlled by a de facto power named <color=#ffd34c>Angel</color>.`,TWN:`根據被俘虜的異教徒供詞，他們似乎有個叫作<color=#ffd34c>天使</color>的背後勢力。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`그들이 운용하던 함선의 종류로 미뤄 볼 때 리플레이서라는 테러 단체와 깊은 연관이 있는 것으로 보입니다.`,JPN:`彼らの使用していた艦船の種類から考えると、
リプレイサーというテロ団体と深い関係があるようです。`,ENG:`And based on the type of ship they were operating, they seem to have a deep connection with a terrorist group called the Replacer Syndicate.`,TWN:`從使用的艦船種類推斷，他們應該與名為克隆集團的恐怖組織有著密切的關係。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`향후 추가적인 정보를 얻게 되면 공유하도록 하겠습니다.`,JPN:`今後追加の情報を入手できたらまた共有します。`,ENG:`We will continue to share any additional intelligence we acquire.`,TWN:`日後要是獲得更多情報，會與各位一同共享。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`충성.`,JPN:`よろしくお願いします。`,ENG:`Thanks again.`,TWN:`你忠實的朋友敬上。`},stage:{bg:`BLACK`,bgm:`THEMA_COFFIN_FULL`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}}];export{e as default};